    theta = 1.0 / (base ** (torch.arange(0, dim, 2, device=device).float() / dim))
    seq_idx = torch.arange(max_seq_len, device=device).float()
    freqs = torch.outer(seq_idx, theta)
    return torch.polar(torch.ones_like(freqs), freqs)

